import React, { useState } from "react"
// import { Helmet } from "react-helmet"
import oriJkoCss from "../css/jko.module.scss"
import { map, some, camelCase, mapKeys } from "lodash"
import clsx from "clsx"

import { withPrefix } from "gatsby"

// code sandbox didn't transform to camelCase for css loader
const jkoCss = mapKeys(oriJkoCss, (s, key) => camelCase(key))

const roleData = {
  doctor: {
    icon: withPrefix("/JKO/img_doctor_90@3x.svg"),
  },
  patient: {
    icon: withPrefix("/JKO/img_patient_90@3x.svg"),
  },
  // baby: {
  // },
  // teacher: {
  // },
}
const defaultFormProps = { action: "", method: "get", target: "_self" }

const RoleCard = ({ role = "role", checked, setValue, icon = "" }) => {
  const handleSelect = e => {
    setValue(role)
  }
  return (
    <div
      className={clsx(
        {
          [jkoCss.selected]: checked,
        },
        jkoCss.roleCardContainer
      )}
      role="radio"
      aria-checked={checked}
      tabIndex="0"
      onClick={handleSelect}
      onKeyPress={handleSelect}
    >
      <div className={jkoCss.roleCard}>
        {icon && <img src={icon} aria-hidden alt="account icon" />}
        <label>{role}</label>
        <input
          type="radio"
          name="account-type"
          value={role}
          checked={checked}
          onChange={handleSelect}
          required
        ></input>
        <span className={jkoCss.checkmark}>✓</span>
      </div>
    </div>
  )
}
const RoleInfo = ({ role = "" }) => {
  return (
    <div
      className={clsx(jkoCss.roleInfo, {
        [jkoCss.hidden]: false,
      })}
    >
      {role ? `Hello ${role}!` : `Choose Account`}
      <br />
      {role
        ? `Please fill out the the form below to get start.`
        : `Please select type above to continue.`}
    </div>
  )
}

const RadioFieldset = ({ legend = "", ...props }) => {
  return (
    <fieldset className={jkoCss.radioFieldset}>
      {legend && <legend className={jkoCss.hAccount}>{legend}</legend>}
      <div className={jkoCss.radioWrap}>{props.children}</div>
    </fieldset>
  )
}
const InputLine = props => {
  const { label, endLink, StartIcon, error, ...rest } = props
  const thisID = `form-input-${label}`
  return (
    <li
      className={clsx(jkoCss.textBox, {
        [jkoCss.invalid]: error,
      })}
    >
      {StartIcon}
      <label className={clsx(jkoCss.textLabel)} htmlFor={thisID}>
        {label}
      </label>
      <input
        className={clsx({ [jkoCss.indented]: Boolean(StartIcon) })}
        id={thisID}
        {...rest}
      />
      {endLink}
      {error && <div className={jkoCss.errorPrompt}>{error}</div>}
    </li>
  )
}

const EndLink = ({ href = "#", title = "", children, ...props }) => {
  return (
    <a href={href} title={title} className={jkoCss.plainLink}>
      {children}
    </a>
  )
}

const StartIcon = ({ url }) => {
  /**
   * Decorating Icon in front of input box,
   * An img element is displayed here.
   * @param {url} String For src data.
   */
  return <img className={jkoCss.startIcon} src={url} alt="" aria-hidden />
}
const InputLineGroup = props => {
  return <ul className={jkoCss.emptyUl}>{props.children}</ul>
}
const NoAccount = ({
  ask = "No account?",
  to = "/",
  title = "Create a new account",
  show = "Signup",
}) => {
  return (
    <span>
      {ask}
      <a href={to} className={jkoCss.plainLink} title={title}>
        {show}
      </a>
    </span>
  )
}
const SubmitGroup = ({
  text = "Login",
  disabled = false,
  appendix = <NoAccount />,
}) => {
  return (
    <div className={jkoCss.submitContainer}>
      <input type="submit" value={text} disabled={disabled} />
      {appendix}
    </div>
  )
}

const checkOverlap = (e, pw, maxLen = 5) => {
  // TODO: use sliding window to get better performance
  if (e.length <= maxLen || pw.length <= maxLen) {
    return false
  }
  for (let i = 0; i < pw.length - maxLen; i++) {
    if (e.includes(pw.substring(i, i + maxLen))) {
      return true
    }
  }
  return false
}

const promiseCheckOverlap = (e, pw, maxLen = 5) => {
  return new Promise((resolve, reject) => {
    const notPass = checkOverlap(e, pw, maxLen)
    if (notPass) {
      reject("Password contain 6+ same characters from email")
    } else {
      resolve(true)
    }
  })
}

const LoginForm = ({ formProps = defaultFormProps, ...props }) => {
  const [roleChoice, setRoleChoice] = useState(false)
  const [email, setEmail] = useState("")
  const [pw, setPw] = useState("")
  const [isOverlap, setIsOverlap] = useState(false)
  const handleEmail = e => {
    setEmail(e?.target?.value)
    setIsOverlap(false)
  }
  const handlePw = e => {
    setPw(e?.target?.value)
    setIsOverlap(false)
  }
  // const handleSubmit = e => {
  //   processForm()
  //   e.preventDefault()
  //   return
  //   let valid = !checkOverlap(email, pw, 5)
  //   if (!valid) {
  //     setIsOverlap(true)
  //     e.preventDefault()
  //   } else {
  //     // Something
  //   }
  // }
  const processForm = async e => {
    e.preventDefault()
    try {
      const notOverlap = await promiseCheckOverlap(email, pw)
      console.log("PW ok.")
      // set Local Storage for autocomplete in radio input
      return notOverlap
    } catch (error) {
      console.log(error)
      setIsOverlap(true)
    }
  }
  return (
    <div className={clsx(jkoCss.container, jkoCss.buildingBg)}>
      <form onSubmit={processForm} {...formProps}>
        <RadioFieldset legend="Choose Account Type">
          {map(roleData, (obj, key) => {
            return (
              <RoleCard
                key={`role-${key}`}
                role={key}
                {...obj}
                setValue={setRoleChoice}
                checked={roleChoice === key}
              />
            )
          })}
        </RadioFieldset>
        <RoleInfo role={roleChoice} />
        <InputLineGroup>
          <InputLine
            placeholder="Email"
            label="Email"
            type="email"
            required
            autoComplete="email"
            value={email}
            onChange={handleEmail}
            StartIcon={<StartIcon url={withPrefix("/JKO/icon-email.svg")} />}
          />
          <InputLine
            placeholder="Password"
            label="Password"
            type="password"
            required
            autoComplete="current-password"
            value={pw}
            onChange={handlePw}
            StartIcon={<StartIcon url={withPrefix("/JKO/icon-pw.svg")} />}
            endLink={
              <EndLink href="/" title="retrieve your password">
                Forgot?
              </EndLink>
            }
            error={
              isOverlap
                ? "Password cannot contain 6 same characters from email"
                : ""
            }
          />
        </InputLineGroup>
        <SubmitGroup
          disabled={some([roleChoice, pw, email], v => !Boolean(v))}
        />
      </form>
    </div>
  )
}

export default LoginForm
export {
  RoleCard,
  RoleInfo,
  InputLine,
  EndLink,
  StartIcon,
  checkOverlap,
  SubmitGroup,
  NoAccount,
  InputLineGroup,
  RadioFieldset,
}
